parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "selected_tool": {
      "type": "string",
      "enum": [
        "Geocode",
        "Buffer",
        "AttributeQuery",
        "AttributeTable",
        "NearestSearch",
        "PointDensity",
        "Intersection",
        "Union",
        "Routing",
        "CoordinateTransform"
      ]
    },
    "explanation": {
      "type": "string"
    },
    "parameters": {
      "type": "object",
      "properties": {
        "location_name": {
          "type": "string"
        },
        "latitude": {
          "type": "string",
          "description": "latitude value (string format to ensure LLM tool call compatibility)"
        },
        "longitude": {
          "type": "string",
          "description": "longitude value (string format to ensure LLM tool call compatibility)"
        },
        "destination_latitude": {
          "type": "string",
          "description": "destination_latitude value"
        },
        "destination_longitude": {
          "type": "string",
          "description": "destination_longitude value"
        },
        "distance_meters": {
          "type": "string",
          "description": "distance_meters value"
        },
        "secondary_distance_meters": {
          "type": "string",
          "description": "secondary_distance_meters value"
        },
        "feature_type": {
          "type": "string"
        },
        "secondary_feature_type": {
          "type": "string"
        }
      },
      "required": [
        "location_name",
        "latitude",
        "longitude"
      ]
    }
  },
  "required": [
    "selected_tool",
    "parameters",
    "explanation"
  ]
}

parameters.jsCode:
// =====================================================================
// GIS ENGINE — TAM YENIDEN YAZIM (crash-proof, 60sn node limitine takilmaz)
// Her model workflow'unda kullanilabilir; sadece asagidaki MODEL_KEY'i degistir.
// =====================================================================
var MODEL_KEY = 'groq';   // Hangi modeldeyse bunu yazın: 'claude' | 'gpt' | 'groq' | 'gemini' | 'deepseek' | 'qwen' | 'glm'

// ---------- 0) Girdi cozumleme ----------
var raw = items[0].json;
var parsed = raw;
if (raw && raw.output !== undefined) { parsed = raw.output; }
if (typeof parsed === 'string') { try { parsed = JSON.parse(parsed); } catch (e) { parsed = {}; } }
if (!parsed || typeof parsed !== 'object') { parsed = {}; }

var p = (parsed.parameters && typeof parsed.parameters === 'object') ? parsed.parameters : {};
var tool = parsed.selected_tool || 'AttributeTable';
var explanation = parsed.explanation || '';

var rawUserMessage = '';
try { rawUserMessage = $('Read Message').first().json.message || ''; } catch (e) { rawUserMessage = ''; }

// ---------- 1) Tur cevirileri ----------
function normalizeFeatureType(name) {
  var n = String(name || '').toLowerCase().trim();
  var map = {
    'eczane': 'pharmacy', 'eczaneler': 'pharmacy', 'eczanenin': 'pharmacy', 'pharmacy': 'pharmacy',
    'hastane': 'hospital', 'hastaneler': 'hospital', 'hospital': 'hospital',
    'kafe': 'cafe', 'kafeler': 'cafe', 'cafe': 'cafe',
    'okul': 'school', 'okullar': 'school', 'school': 'school',
    'market': 'supermarket', 'marketler': 'supermarket', 'supermarket': 'supermarket',
    'sukermarket': 'supermarket', 'supermarketler': 'supermarket',
    'park': 'park', 'parklar': 'park',
    'banka': 'bank', 'bankalar': 'bank', 'bank': 'bank',
    'restoran': 'restaurant', 'restoranlar': 'restaurant', 'restaurant': 'restaurant',
    'cami': 'place_of_worship', 'camii': 'place_of_worship', 'camiler': 'place_of_worship', 'place_of_worship': 'place_of_worship',
    'otobus': 'bus_station', 'bus_station': 'bus_station',
    'benzin': 'fuel', 'fuel': 'fuel',
    'atm': 'atm',
    'otel': 'hotel', 'oteller': 'hotel', 'hotel': 'hotel',
    'muze': 'museum', 'museum': 'museum'
  };
  return map[n] || n;
}

function detectFeatureTypesFromText(text) {
  var t = String(text || '').toLocaleLowerCase('tr-TR');
  var roots = [
    ['eczane', 'pharmacy'], ['hastane', 'hospital'], ['kafe', 'cafe'], ['cafe', 'cafe'],
    ['okul', 'school'], ['süpermarket', 'supermarket'], ['market', 'supermarket'], ['supermarket', 'supermarket'],
    ['park', 'park'], ['banka', 'bank'], ['bank', 'bank'], ['restoran', 'restaurant'], ['restaurant', 'restaurant'],
    ['cami', 'place_of_worship'], ['durağ', 'bus_station'], ['otobüs', 'bus_station'],
    ['benzin', 'fuel'], ['akaryakıt', 'fuel'], ['atm', 'atm'], ['otel', 'hotel'], ['hotel', 'hotel'],
    ['müze', 'museum'], ['museum', 'museum']
  ];
  var found = [];
  for (var i = 0; i < roots.length; i++) {
    var idx = t.indexOf(roots[i][0]);
    if (idx !== -1) found.push({ idx: idx, type: roots[i][1] });
  }
  found.sort(function (a, b) { return a.idx - b.idx; });
  var ordered = [];
  for (var j = 0; j < found.length; j++) { if (ordered.indexOf(found[j].type) === -1) ordered.push(found[j].type); }
  return ordered;
}

var primary = normalizeFeatureType(p.feature_type || '');
var secondary = normalizeFeatureType(p.secondary_feature_type || '');
if (!primary || !secondary) {
  var detected = detectFeatureTypesFromText(rawUserMessage);
  if (!primary && detected[0]) primary = detected[0];
  if (!secondary && detected[1] && detected[1] !== primary) secondary = detected[1];
}

var distance = Number(p.distance_meters) || 500;
var secondaryDistance = Number(p.secondary_distance_meters) || distance;
var lat = Number(p.latitude);
var lon = Number(p.longitude);
var loc = String(p.location_name || '').replace(/"/g, '').trim();

function osmTag(name) {
  var n = String(name || '').toLowerCase();
  var map = {
    'park': ['leisure', 'park'], 'playground': ['leisure', 'playground'], 'garden': ['leisure', 'garden'],
    'sports_centre': ['leisure', 'sports_centre'], 'stadium': ['leisure', 'stadium'],
    'supermarket': ['shop', 'supermarket'], 'mall': ['shop', 'mall'], 'convenience': ['shop', 'convenience'], 'bakery': ['shop', 'bakery'],
    'hotel': ['tourism', 'hotel'], 'museum': ['tourism', 'museum']
  };
  if (map[n]) return map[n];
  return ['amenity', n];
}

// ---------- 2) Zaman butcesi & guvenli HTTP ----------
var t0 = Date.now();
var DEADLINE = t0 + 45000;                 // 45 sn sert ust sinir
var httpRequest = this.helpers.httpRequest.bind(this.helpers);

function sleep(ms) { return new Promise(function (r) { setTimeout(r, ms); }); }

var lastOverpassError = ''; 

async function overpassQuery(req, body, deadline) {
  // Hizli alternatiflerin yer aldigi sunucu listesi (Mirror List)
  var endpoints = [
    'https://overpass-api.de/api/interpreter',
    'https://lz4.overpass-api.de/api/interpreter',
    'https://z.overpass-api.de/api/interpreter',
    'https://overpass.kumi.systems/api/interpreter'
  ];
  for (var k = 0; k < endpoints.length; k++) {
    var remaining = deadline - Date.now();
    if (remaining < 3000) return null;
    // Bekleme süresini 8 saniyeye çıkardık
    var perTimeout = Math.min(8000, remaining - 500);
    if (perTimeout < 1500) return null;
    try {
      var resp = await req({
        method: 'POST', url: endpoints[k],
        body: 'data=' + encodeURIComponent(body),
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        json: false, timeout: perTimeout
      });
      var data = typeof resp === 'string' ? JSON.parse(resp) : resp;
      if (data && Array.isArray(data.elements)) return data.elements;
      lastOverpassError = 'Beklenmeyen yanit (elements yok): ' + String(resp).slice(0, 200);
    } catch (e) {
      var msg = (e && e.message) ? e.message : String(e);
      var sc = (e && (e.statusCode || (e.response && e.response.statusCode))) || '';
      var bodyErr = '';
      try { bodyErr = e && e.response && e.response.body ? String(e.response.body).slice(0, 200) : ''; } catch (ee) {}
      lastOverpassError = endpoints[k] + ' -> ' + (sc ? ('HTTP ' + sc + ' | ') : '') + msg + (bodyErr ? (' | ' + bodyErr) : '');
      if (deadline - Date.now() > 4000) { await sleep(300); }
    }
  }
  return null;
}

function overpassEscape(s) { return String(s || '').replace(/[\"\\]/g, ''); }

// ---------- 3) OSM'den nesneleri cek ----------
var elements = [];
var fetchFailed = false;

if ((primary || secondary) && !isNaN(lat) && !isNaN(lon)) {
  await sleep(Math.floor(Math.random() * 500));

  var t1 = primary ? osmTag(primary) : null;
  var t2 = secondary ? osmTag(secondary) : null;
  var searchRadius = Math.max(3000, distance * 5);
  var around = '(around:' + searchRadius + ',' + lat + ',' + lon + ')';

  var gotAnswer = false;

  if (loc) {
    var innerArea = '';
    if (t1) innerArea += 'node(area.a)[' + t1[0] + '=' + t1[1] + '];way(area.a)[' + t1[0] + '=' + t1[1] + '];';
    if (t2) innerArea += 'node(area.a)[' + t2[0] + '=' + t2[1] + '];way(area.a)[' + t2[0] + '=' + t2[1] + '];';
    var areaBody = '[out:json][timeout:10];area["name"="' + overpassEscape(loc) + '"]["boundary"="administrative"]->.a;(' + innerArea + ');out center;';
    var areaEls = await overpassQuery(httpRequest, areaBody, Math.min(DEADLINE, Date.now() + 12000));
    if (areaEls !== null) { gotAnswer = true; if (areaEls.length > 0) elements = areaEls; }
  }

  if (elements.length === 0) {
    var innerRad = '';
    if (t1) innerRad += 'node[' + t1[0] + '=' + t1[1] + ']' + around + ';way[' + t1[0] + '=' + t1[1] + ']' + around + ';';
    if (t2) innerRad += 'node[' + t2[0] + '=' + t2[1] + ']' + around + ';way[' + t2[0] + '=' + t2[1] + ']' + around + ';';
    var radBody = '[out:json][timeout:15];(' + innerRad + ');out center;';
    var radEls = await overpassQuery(httpRequest, radBody, DEADLINE);
    if (radEls !== null) { gotAnswer = true; elements = radEls; }
  }

  if (!gotAnswer) fetchFailed = true;
}

// ---------- 4) Geometri yardimcilari ----------
function destPoint(la, lo, d, br) {
  var R = 6371000, brng = br * Math.PI / 180, la1 = la * Math.PI / 180, lo1 = lo * Math.PI / 180, dByR = d / R;
  var la2 = Math.asin(Math.sin(la1) * Math.cos(dByR) + Math.cos(la1) * Math.sin(dByR) * Math.cos(brng));
  var lo2 = lo1 + Math.atan2(Math.sin(brng) * Math.sin(dByR) * Math.cos(la1), Math.cos(dByR) - Math.sin(la1) * Math.sin(la2));
  return [lo2 * 180 / Math.PI, la2 * 180 / Math.PI];
}
function haversine(la1, lo1, la2, lo2) {
  var R = 6371000, dLat = (la2 - la1) * Math.PI / 180, dLon = (lo2 - lo1) * Math.PI / 180;
  var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.cos(la1 * Math.PI / 180) * Math.cos(la2 * Math.PI / 180) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}
function bufferRing(la, lo, d) { var r = []; for (var b = 0; b <= 360; b += 15) r.push(destPoint(la, lo, d, b)); return r; }
function matchesTag(el, name) { if (!name || !el.tags) return false; var tg = osmTag(name); return el.tags[tg[0]] === tg[1]; }
function elementCoords(el) {
  if (el.lat !== undefined && el.lon !== undefined) return [el.lon, el.lat];
  if (el.center) return [el.center.lon, el.center.lat];
  return null;
}

// ── KOORDINAT / DATUM DONUSUM YARDIMCISI (ONLINE API + LOCAL FALLBACK) ──
async function performCoordinateTransform(lo, la, sourceCRS, targetCRS, reqHelper) {
  var cleanSrc = String(sourceCRS || '4326').toUpperCase().replace('EPSG:', '').trim();
  var cleanTgt = String(targetCRS || '3857').toUpperCase().replace('EPSG:', '').trim();
  var isTargetGeographic = (cleanTgt === '4326' || cleanTgt === 'WGS84');

  if (cleanSrc === cleanTgt) {
    return { 
      x: lo, 
      y: la, 
      label_x: isTargetGeographic ? 'transformed_longitude' : 'transformed_x_meters', 
      label_y: isTargetGeographic ? 'transformed_latitude' : 'transformed_y_meters', 
      method: 'same' 
    };
  }

  try {
    var url = 'https://epsg.io/trans?x=' + lo + '&y=' + la + '&s_srs=' + cleanSrc + '&t_srs=' + cleanTgt;
    var resp = await reqHelper({ method: 'GET', url: url, json: true, timeout: 4000 });
    if (resp && resp.x !== undefined && resp.y !== undefined) {
      return {
        x: isTargetGeographic ? Math.round(Number(resp.x) * 1000000) / 1000000 : Math.round(Number(resp.x) * 100) / 100,
        y: isTargetGeographic ? Math.round(Number(resp.y) * 1000000) / 1000000 : Math.round(Number(resp.y) * 100) / 100,
        label_x: isTargetGeographic ? 'transformed_longitude' : 'transformed_latitude',
        label_y: isTargetGeographic ? 'transformed_latitude' : 'transformed_y_meters',
        method: 'epsg_io_api'
      };
    }
  } catch (e) {}

  var target = cleanTgt.toLowerCase();
  if (target === 'grs80' || target === '4230' || target === 'ed50') {
    var dx = 84.0, dy = -37.0, dz = -123.0; 
    var a = 6378137.0, f = 1.0 / 298.257223563;
    var esq = 2 * f - f * f;
    var phi = la * Math.PI / 180;
    var lam = lo * Math.PI / 180;
    var sinPhi = Math.sin(phi), cosPhi = Math.cos(phi);
    var nu = a / Math.sqrt(1 - esq * sinPhi * sinPhi);
    var x = nu * cosPhi * Math.cos(lam) + dx;
    var y = nu * cosPhi * Math.sin(lam) + dy;
    var z = nu * (1 - esq) * sinPhi + dz;
    var a_g = 6378137.0, f_g = 1.0 / 298.257222101; 
    var esq_g = 2 * f_g - f_g * f_g;
    var p_rad = Math.sqrt(x*x + y*y);
    var phi_g = Math.atan2(z, p_rad * (1 - esq_g));
    for (var it = 0; it < 5; it++) {
      var sinPhiG = Math.sin(phi_g);
      var nu_g = a_g / Math.sqrt(1 - esq_g * sinPhiG * sinPhiG);
      phi_g = Math.atan2(z + esq_g * nu_g * sinPhiG, p_rad);
    }
    return {
      x: Math.round((Math.atan2(y, x) * 180 / Math.PI) * 1000000) / 1000000,
      y: Math.round((phi_g * 180 / Math.PI) * 1000000) / 1000000,
      label_x: 'transformed_longitude',
      label_y: 'transformed_latitude',
      method: 'local_helmert'
    };
  }

  var R_w = 6378137.0;
  var mx = R_w * lo * Math.PI / 180;
  var my = R_w * Math.log(Math.tan(Math.PI / 4 + la * Math.PI / 360));
  return {
    x: Math.round(mx * 100) / 100,
    y: Math.round(my * 100) / 100,
    label_x: 'transformed_x_meters',
    label_y: 'transformed_y_meters',
    method: 'local_mercator'
  };
}

// ---------- 5) Nesneleri ayikla ----------
var primaryFeats = [], secondaryFeats = [];
for (var i2 = 0; i2 < elements.length; i2++) {
  var el = elements[i2];
  if (!el.tags) continue;
  var c = elementCoords(el);
  if (!c) continue;
  var feat = {
    type: 'Feature',
    properties: {
      name: el.tags.name || '(adsiz)',
      type: el.tags.amenity || el.tags.leisure || el.tags.shop || el.tags.tourism || '',
      latitude: c[1], longitude: c[0]
    },
    geometry: { type: 'Point', coordinates: c }
  };
  if (primary && matchesTag(el, primary)) primaryFeats.push(feat);
  if (secondary && matchesTag(el, secondary)) secondaryFeats.push(feat);
}

// ---------- 6) Araclar ----------
var resultFeatures = [], attributeTable = [];
var toolLower = String(tool).toLowerCase();

if (toolLower === 'geocode' && !isNaN(lat) && !isNaN(lon)) {
  resultFeatures.push({ type: 'Feature', properties: { name: loc, type: 'center', latitude: lat, longitude: lon }, geometry: { type: 'Point', coordinates: [lon, lat] } });
  attributeTable.push({ name: loc, type: 'center', latitude: lat, longitude: lon });

} else if (toolLower === 'coordinatetransform') {
  var srcCRS = p.source_crs || 'EPSG:4326';
  var tgtCRS = p.target_crs || 'EPSG:3857';
  var queryLower = rawUserMessage.toLowerCase();

  var epsgMatches = queryLower.match(/epsg\s*[:\s]*(\d+)/g);
  if (epsgMatches && epsgMatches.length >= 2) {
    srcCRS = epsgMatches[0].replace(/[\s:]/g, '').toUpperCase();
    tgtCRS = epsgMatches[1].replace(/[\s:]/g, '').toUpperCase();
  } else if (queryLower.indexOf('4326') !== -1 && (queryLower.indexOf('grs80') !== -1 || queryLower.indexOf('grs 80') !== -1)) {
    srcCRS = 'EPSG:4326';
    tgtCRS = 'GRS80';
  } else if (queryLower.indexOf('3857') !== -1 && queryLower.indexOf('4326') !== -1) {
    srcCRS = 'EPSG:3857';
    tgtCRS = 'EPSG:4326';
  }

  if (!isNaN(lat) && !isNaN(lon)) {
    var tcCenter = await performCoordinateTransform(lon, lat, srcCRS, tgtCRS, httpRequest);
    resultFeatures.push({ type: 'Feature', properties: { name: loc + " (Merkez)", type: 'center', latitude: lat, longitude: lon }, geometry: { type: 'Point', coordinates: [lon, lat] } });
    var centerRow = { name: loc + " (Merkez)", source_crs: srcCRS, target_crs: tgtCRS };
    centerRow[tcCenter.label_x] = tcCenter.x;
    centerRow[tcCenter.label_y] = tcCenter.y;
    attributeTable.push(centerRow);
  }

  for (var m = 0; m < primaryFeats.length; m++) {
    var pf = primaryFeats[m];
    var tcNode = await performCoordinateTransform(pf.geometry.coordinates[0], pf.geometry.coordinates[1], srcCRS, tgtCRS, httpRequest);
    resultFeatures.push(pf);
    var nodeRow = { name: pf.properties.name, source_crs: srcCRS, target_crs: tgtCRS };
    nodeRow[tcNode.label_x] = tcNode.x;
    nodeRow[tcNode.label_y] = tcNode.y;
    attributeTable.push(nodeRow);
  }
  explanation = (explanation || '') + ' (' + srcCRS + ' CRS kodundan ' + tgtCRS + ' CRS koduna koordinat donusumu yapildi.)';

} else if (toolLower === 'routing' && !isNaN(lat) && !isNaN(lon)) {
  var stops = secondaryFeats.length > 0 ? secondaryFeats.slice() : primaryFeats.slice();
  if (stops.length === 0 && !isNaN(Number(p.destination_latitude)) && !isNaN(Number(p.destination_longitude))) {
    stops = [{ type: 'Feature', properties: { name: 'Hedef', type: '' }, geometry: { type: 'Point', coordinates: [Number(p.destination_longitude), Number(p.destination_latitude)] } }];
  }
  if (stops.length > 8) stops = stops.slice(0, 8);
  var ordered = [], curLat = lat, curLon = lon, remaining2 = stops.slice();
  while (remaining2.length > 0) {
    var bi = 0, bd = Infinity;
    for (var ri = 0; ri < remaining2.length; ri++) {
      var dr = haversine(curLat, curLon, remaining2[ri].geometry.coordinates[1], remaining2[ri].geometry.coordinates[0]);
      if (dr < bd) { bd = dr; bi = ri; }
    }
    var nxt = remaining2.splice(bi, 1)[0];
    ordered.push(nxt); curLat = nxt.geometry.coordinates[1]; curLon = nxt.geometry.coordinates[0];
  }
  if (ordered.length > 0 && (DEADLINE - Date.now()) > 6000) {
    var coordsList = [lon + ',' + lat];
    for (var oi = 0; oi < ordered.length; oi++) coordsList.push(ordered[oi].geometry.coordinates[0] + ',' + ordered[oi].geometry.coordinates[1]);
    var url = 'https://router.project-osrm.org/route/v1/driving/' + coordsList.join(';') + '?overview=full&geometries=geojson';
    try {
      var rr = await httpRequest({ method: 'GET', url: url, json: true, timeout: Math.min(12000, DEADLINE - Date.now() - 1000) });
      if (rr && rr.routes && rr.routes.length > 0) {
        var rt = rr.routes[0];
        resultFeatures.push({ type: 'Feature', properties: { name: loc, type: 'start', sequence: 0, latitude: lat, longitude: lon }, geometry: { type: 'Point', coordinates: [lon, lat] } });
        for (var oi2 = 0; oi2 < ordered.length; oi2++) {
          var st = ordered[oi2];
          resultFeatures.push({ type: 'Feature', properties: { name: st.properties.name, type: 'stop', sequence: oi2 + 1, latitude: st.geometry.coordinates[1], longitude: st.geometry.coordinates[0] }, geometry: { type: 'Point', coordinates: st.geometry.coordinates } });
          attributeTable.push({ sequence: oi2 + 1, name: st.properties.name, latitude: st.geometry.coordinates[1], longitude: st.geometry.coordinates[0] });
        }
        resultFeatures.push({ type: 'Feature', properties: { type: 'route', total_distance_km: Math.round(rt.distance / 100) / 10, total_duration_min: Math.round(rt.duration / 60), stops_count: ordered.length }, geometry: rt.geometry });
        attributeTable.unshift({ sequence: 'TOPLAM', name: ordered.length + ' durak', latitude: '-', longitude: '-', total_km: Math.round(rt.distance / 100) / 10, total_min: Math.round(rt.duration / 60) });
      }
    } catch (e) { }
  }

} else if (toolLower === 'buffer' && !isNaN(lat) && !isNaN(lon)) {
  if (primaryFeats.length > 0) {
    for (var kk = 0; kk < primaryFeats.length; kk++) {
      var f = primaryFeats[kk];
      resultFeatures.push(f);
      resultFeatures.push({ type: 'Feature', properties: { type: 'buffer', source: f.properties.name, distance_meters: distance }, geometry: { type: 'Polygon', coordinates: [bufferRing(f.geometry.coordinates[1], f.geometry.coordinates[0], distance)] } });
      attributeTable.push(f.properties);
    }
    explanation = (explanation || '') + ' (' + primaryFeats.length + ' adet bulundu; her birine ' + distance + 'm tampon cizildi.)';
  } else {
    explanation = fetchFailed
      ? ('Veri kaynagina (OpenStreetMap/Overpass) ulasilamadi. Teshis: ' + (lastOverpassError || 'bilinmiyor'))
      : ('"' + loc + '" sinirlari icinde "' + primary + '" turunde nesne bulunamadi.');
  }

} else if (toolLower === 'nearestsearch' && primaryFeats.length > 0 && secondaryFeats.length > 0) {
  for (var n = 0; n < primaryFeats.length; n++) {
    var pf = primaryFeats[n], best = null, bestDist = Infinity;
    for (var s2 = 0; s2 < secondaryFeats.length; s2++) {
      var sf = secondaryFeats[s2];
      var dd = haversine(pf.geometry.coordinates[1], pf.geometry.coordinates[0], sf.geometry.coordinates[1], sf.geometry.coordinates[0]);
      if (dd < bestDist) { bestDist = dd; best = sf; }
    }
    resultFeatures.push(pf);
    if (best) {
      resultFeatures.push(best);
      resultFeatures.push({ type: 'Feature', properties: { type: 'connection', distance_meters: Math.round(bestDist) }, geometry: { type: 'LineString', coordinates: [pf.geometry.coordinates, best.geometry.coordinates] } });
      attributeTable.push({ from: pf.properties.name, from_lat: pf.geometry.coordinates[1], from_lon: pf.geometry.coordinates[0], to: best.properties.name, to_lat: best.geometry.coordinates[1], to_lon: best.geometry.coordinates[0], distance_meters: Math.round(bestDist) });
    }
  }

} else if ((toolLower === 'intersection' || toolLower === 'union') && primaryFeats.length > 0 && secondaryFeats.length > 0) {
  for (var pi = 0; pi < primaryFeats.length; pi++) {
    for (var si = 0; si < secondaryFeats.length; si++) {
      var pp = primaryFeats[pi], ss = secondaryFeats[si];
      var dd2 = haversine(pp.geometry.coordinates[1], pp.geometry.coordinates[0], ss.geometry.coordinates[1], ss.geometry.coordinates[0]);
      var overlap = dd2 <= (distance + secondaryDistance);
      if ((toolLower === 'intersection' && overlap) || toolLower === 'union') {
        resultFeatures.push(pp, ss);
        if (toolLower === 'intersection') {
          var intersectionCoords = [];
          var steps = 32;
          for (var idx = 0; idx < steps; idx++) {
            var angle = (idx * 360) / steps;
            var pt1 = destPoint(pp.geometry.coordinates[1], pp.geometry.coordinates[0], distance, angle);
            var dToSec = haversine(pt1[1], pt1[0], ss.geometry.coordinates[1], ss.geometry.coordinates[0]);
            if (dToSec <= secondaryDistance) {
              intersectionCoords.push(pt1);
            }
          }
          for (var idx = 0; idx < steps; idx++) {
            var angle = (idx * 360) / steps;
            var pt2 = destPoint(ss.geometry.coordinates[1], ss.geometry.coordinates[0], secondaryDistance, angle);
            var dToPri = haversine(pt2[1], pt2[0], pp.geometry.coordinates[1], pp.geometry.coordinates[0]);
            if (dToPri <= distance) {
              intersectionCoords.push(pt2);
            }
          }
          if (intersectionCoords.length >= 3) {
            var sumX = 0, sumY = 0;
            for (var cIdx = 0; cIdx < intersectionCoords.length; cIdx++) {
              sumX += intersectionCoords[cIdx][0];
              sumY += intersectionCoords[cIdx][1];
            }
            var centerX = sumX / intersectionCoords.length;
            var centerY = sumY / intersectionCoords.length;
            intersectionCoords.sort(function (a, b) {
              return Math.atan2(a[1] - centerY, a[0] - centerX) - Math.atan2(b[1] - centerY, b[0] - centerX);
            });
            intersectionCoords.push(intersectionCoords[0]);
            resultFeatures.push({
              type: 'Feature',
              properties: {
                type: 'buffer',
                source: pp.properties.name + ' - ' + ss.properties.name + ' Kesisimi',
                distance_meters: dd2
              },
              geometry: { type: 'Polygon', coordinates: [intersectionCoords] }
            });
          }
        }
        attributeTable.push({ primary: pp.properties.name, secondary: ss.properties.name, distance_meters: Math.round(dd2), overlap: overlap });
      }
    }
  }

} else if (toolLower.indexOf('density') !== -1 || toolLower.indexOf('heatmap') !== -1 || toolLower.indexOf('kde') !== -1) {
  var searchRadius = distance || 500;

  if (primaryFeats.length > 0) {
    // 1) Sınır kutusu (Bounding box) bul
    var minLat = Infinity, maxLat = -Infinity, minLon = Infinity, maxLon = -Infinity;
    for (var fIdx = 0; fIdx < primaryFeats.length; fIdx++) {
      var coords = primaryFeats[fIdx].geometry.coordinates;
      if (coords[0] < minLon) minLon = coords[0];
      if (coords[0] > maxLon) maxLon = coords[0];
      if (coords[1] < minLat) minLat = coords[1];
      if (coords[1] > maxLat) maxLat = coords[1];
    }

    // Arama yarıçapı kadar genişlet (111000m = ~1 derece)
    var padding = (searchRadius / 111000) * 1.5;
    minLat -= padding; maxLat += padding;
    var cosLat = Math.cos(minLat * Math.PI / 180) || 1;
    minLon -= padding / cosLat; maxLon += padding / cosLat;

    // 2) Grid oluştur (Daha yüksek çözünürlük için 40x40 çözünürlük)
    var Nx = 40;
    var Ny = 40;
    var dx = (maxLon - minLon) / Nx;
    var dy = (maxLat - minLat) / Ny;

    var grid = [];
    var maxVal = 0;

    for (var i = 0; i < Nx; i++) {
      for (var j = 0; j < Ny; j++) {
        var cx = minLon + (i + 0.5) * dx;
        var cy = minLat + (j + 0.5) * dy;

        // Kernel Yoğunluğu Hesapla (Quartic/Biweight Kernel)
        var val = 0;
        for (var pIdx = 0; pIdx < primaryFeats.length; pIdx++) {
          var pf = primaryFeats[pIdx];
          var dist = haversine(cy, cx, pf.geometry.coordinates[1], pf.geometry.coordinates[0]);
          if (dist <= searchRadius) {
            var u = dist / searchRadius;
            val += (1 - u*u) * (1 - u*u);
          }
        }

        grid.push({ i: i, j: j, cx: cx, cy: cy, val: val });
        if (val > maxVal) maxVal = val;
      }
    }

    // 3) 10 Seviyeli Poligonları üret ve Öznitelik tablosunu doldur
    if (maxVal > 0) {
      for (var gIdx = 0; gIdx < grid.length; gIdx++) {
        var cell = grid[gIdx];
        if (cell.val <= 0.02 * maxVal) continue; // Çok düşük yoğunluklu hücreleri çizme

        var ratio = cell.val / maxVal;
        var level = 'level1';

        if (ratio >= 0.90) level = 'level10';
        else if (ratio >= 0.80) level = 'level9';
        else if (ratio >= 0.70) level = 'level8';
        else if (ratio >= 0.60) level = 'level7';
        else if (ratio >= 0.50) level = 'level6';
        else if (ratio >= 0.40) level = 'level5';
        else if (ratio >= 0.30) level = 'level4';
        else if (ratio >= 0.20) level = 'level3';
        else if (ratio >= 0.10) level = 'level2';

        // Kare hücresini oluştur
        var x1 = cell.cx - dx * 0.51;
        var x2 = cell.cx + dx * 0.51;
        var y1 = cell.cy - dy * 0.51;
        var y2 = cell.cy + dy * 0.51;

        resultFeatures.push({
          type: 'Feature',
          properties: { 
            type: 'buffer', 
            density: level,
            density_value: Math.round(ratio * 100) / 100
          },
          geometry: {
            type: 'Polygon',
            coordinates: [[
              [x1, y1],
              [x2, y1],
              [x2, y2],
              [x1, y2],
              [x1, y1]
            ]]
          }
        });

        // Öznitelik tablosuna her bir yoğunluk hücresini yaz
        attributeTable.push({
          konum: (Math.round(cell.cy * 10000) / 10000) + ", " + (Math.round(cell.cx * 10000) / 10000),
          yogunluk_seviyesi: level.toUpperCase().replace('LEVEL', 'Seviye '),
          yogunluk_orani: Math.round(ratio * 100) + "%",
          yogunluk_skoru: Math.round(cell.val * 100) / 100
        });
      }

      // Tabloyu en yüksek skordan en düşüğe doğru sırala
      attributeTable.sort(function(a, b) { return b.yogunluk_skoru - a.yogunluk_skoru; });
    }
  }
  explanation = (explanation || '') + ' (' + primaryFeats.length + ' nokta uzerinde 10 seviyeli Kernel Density analizi hesaplandi.)';

} else {
  resultFeatures = primaryFeats;
  for (var m = 0; m < primaryFeats.length; m++) attributeTable.push(primaryFeats[m].properties);
  if (primaryFeats.length === 0 && fetchFailed && !explanation) {
    explanation = 'Veri kaynagina (OpenStreetMap/Overpass) su an ulasilamadi. Lutfen tekrar deneyin.';
  }
}

// ---------- 7) Token/maliyet tahmini ----------
var inputCharsTotal = 2500 + ((parsed.parameters && parsed.parameters.location_name) ? 80 : 60) + 800;
var outputCharsTotal = JSON.stringify(parsed).length;
var prompt_tokens = Math.round(inputCharsTotal / 4);
var completion_tokens = Math.round(outputCharsTotal / 4);
var pricing = {
  'claude': { input: 3.00, output: 15.00 }, 'gpt': { input: 0.15, output: 0.60 },
  'groq': { input: 0.59, output: 0.79 }, 'gemini': { input: 0.075, output: 0.30 },
  'deepseek': { input: 0.14, output: 0.28 }, 'qwen': { input: 0, output: 0 },
  'kimi': { input: 0, output: 0 }, 'glm': { input: 0, output: 0 }
};
var price = pricing[MODEL_KEY] || { input: 0, output: 0 };
var cost_usd = (prompt_tokens * price.input + completion_tokens * price.output) / 1000000;

// ---------- 8) Cikti ----------
var status = resultFeatures.length > 0 ? 'success' : (fetchFailed ? 'error' : 'empty');

return [{
  json: {
    model: MODEL_KEY,
    selected_tool: tool,
    explanation: explanation,
    parameters: p,
    geojson: { type: 'FeatureCollection', features: resultFeatures },
    attribute_table: attributeTable,
    feature_count: resultFeatures.length,
    processing_time_ms: Date.now() - t0,
    debug_overpass: lastOverpassError,
    usage: {
      prompt_tokens: prompt_tokens,
      completion_tokens: completion_tokens,
      total_tokens: prompt_tokens + completion_tokens,
      estimated_cost_usd: Math.round(cost_usd * 1000000) / 1000000
    },
    status: status
  }
}];
